#include <cstdio>
#include <omp.h>

#define N 1024

int main() {
    int *dist = new int[N * N];

    // Initialize the distance matrix
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (i == j)
                dist[i * N + j] = 0;
            else
                dist[i * N + j] = 1000000;  // large number denotes no path
        }
    }

    // Example: add some edges (this should be replaced by actual input)
    for (int i = 0; i < N - 1; i++) {
        dist[i * N + i + 1] = 1;
        dist[(i + 1) * N + i] = 1;
    }

    // Floyd-Warshall algorithm with OpenMP target offload
    for (int k = 0; k < N; k++) {
        #pragma omp target teams distribute parallel for collapse(2) map(tofrom: dist[0:N*N])
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                int newdist = dist[i * N + k] + dist[k * N + j];
                if (newdist < dist[i * N + j]) {
                    dist[i * N + j] = newdist;
                }
            }
        }
    }

    // Print shortest distance from node 0 to node N-1
    printf("Shortest distance from 0 to %d: %d\n", N-1, dist[(N-1)]);

    delete[] dist;
    return 0;
}
